// src/components/cards/NumericCard.jsx
import React from "react";

export function NumericCard({ label, value, highlight = false, color = "default" }) {
  const bgColor = highlight
    ? "bg-red-100"
    : color === "red"
    ? "bg-red-200"
    : color === "green"
    ? "bg-green-200"
    : "bg-gray-100";

  const borderClass =
    color === "red"
      ? "border-red-500"
      : color === "green"
      ? "border-green-500"
      : "border-gray-400";

  return (
    <div className={`glass-panel p-4 rounded-xl border-l-4 ${borderClass} ${bgColor}`}>
      <span className="text-xs font-mono text-outline uppercase">{label}</span>
      <div className="text-3xl font-bold mt-1">{value}</div>
    </div>
  );
}
